import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { useCart } from "../context/CartContext";
import { useAuth } from "../context/AuthContext";
import "../styles/Cart.css";

const ArrowLeftIcon = () => (
  <svg viewBox="0 0 24 24" fill="none" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" stroke="currentColor" width="16" height="16">
    <path d="M19 12H5M5 12l7 7M5 12l7-7" />
  </svg>
);

const TrashIcon = () => (
  <svg viewBox="0 0 24 24" fill="none" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" stroke="currentColor" width="15" height="15">
    <polyline points="3 6 5 6 21 6" />
    <path d="M19 6l-1 14H6L5 6" />
    <path d="M10 11v6M14 11v6" />
    <path d="M9 6V4h6v2" />
  </svg>
);

const CartPage = () => {
  const { cart, removeFromCart, updateQuantity } = useCart();
  const { user } = useAuth();
  const navigate = useNavigate();

  const [selectedItems, setSelectedItems] = useState([]);

  const toggleItem = (item) => {
    const exists = selectedItems.find(i =>
      i.id === item.id &&
      i.selectedSize === item.selectedSize &&
      i.selectedColor === item.selectedColor
    );
    if (exists) {
      setSelectedItems(selectedItems.filter(i =>
        !(i.id === item.id &&
          i.selectedSize === item.selectedSize &&
          i.selectedColor === item.selectedColor)
      ));
    } else {
      setSelectedItems([...selectedItems, item]);
    }
  };

  const isSelected = (item) =>
    selectedItems.some(i =>
      i.id === item.id &&
      i.selectedSize === item.selectedSize &&
      i.selectedColor === item.selectedColor
    );

  const getSelectedTotal = () =>
    selectedItems.reduce((total, item) => {
      const price = parseFloat(String(item.price).replace("$", ""));
      return total + price * item.quantity;
    }, 0);

  const handlePayment = async () => {
    if (selectedItems.length === 0) {
      alert("Please select items to pay");
      return;
    }
    const res = await fetch("http://localhost:5050/api/payment/create-checkout", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ items: selectedItems, email: user?.email }),
    });
    const data = await res.json();
    if (data.url) window.location.href = data.url;
  };

  const toggleAll = () => {
    if (selectedItems.length === cart.items.length) {
      setSelectedItems([]);
    } else {
      setSelectedItems([...cart.items]);
    }
  };

  return (
    <div className="cart-page">

      {/* NAVBAR */}
      <nav className="cart-navbar">
        <div className="cart-navbar-inner">
          <span className="cart-navbar-logo">AURI</span>
        </div>
      </nav>

      <div className="cart-content">

        {/* BACK + HEADING */}
        <div className="cart-header">
          <button className="cart-back-btn" onClick={() => navigate(-1)}>
            <ArrowLeftIcon /> Back
          </button>
          <div className="cart-title-block">
            <h1 className="cart-title">Shopping Cart</h1>
            <span className="cart-count">{cart.items.length} {cart.items.length === 1 ? "item" : "items"}</span>
          </div>
        </div>

        {cart.items.length === 0 ? (
          <div className="cart-empty">
            <h2>Your cart is empty</h2>
            <p>Explore our collection to add items</p>
          </div>
        ) : (
          <div className="cart-layout">

            {/* LEFT — Items */}
            <div className="cart-items-panel">

              {/* Select all row */}
              <div className="cart-select-all-row">
                <label className="cart-custom-checkbox">
                  <input
                    type="checkbox"
                    checked={selectedItems.length === cart.items.length && cart.items.length > 0}
                    onChange={toggleAll}
                  />
                  <span className="cart-checkmark" />
                  <span className="cart-select-all-label">Select All</span>
                </label>
              </div>

              {cart.items.map((item, index) => (
                <div
                  className={`cart-item ${isSelected(item) ? "cart-item--selected" : ""}`}
                  key={index}
                  style={{ animationDelay: `${index * 60}ms` }}
                >
                  {/* Checkbox */}
                  <label className="cart-custom-checkbox">
                    <input
                      type="checkbox"
                      checked={isSelected(item)}
                      onChange={() => toggleItem(item)}
                    />
                    <span className="cart-checkmark" />
                  </label>

                  {/* Image */}
                  <img src={item.img} alt={item.title} className="cart-item-img" />

                  {/* Info */}
                  <div className="cart-info">
                    <h3 className="cart-item-title">{item.title}</h3>
                    <p className="cart-item-meta">{item.selectedSize} · {item.selectedColor}</p>
                    <p className="cart-item-price">{item.price}</p>
                  </div>

                  {/* Quantity */}
                  <div className="cart-quantity">
                    <button
                      className="cart-qty-btn"
                      onClick={() => updateQuantity(item, item.quantity - 1)}
                      aria-label="Decrease quantity"
                    >−</button>
                    <span className="cart-qty-value">{item.quantity}</span>
                    <button
                      className="cart-qty-btn"
                      onClick={() => updateQuantity(item, item.quantity + 1)}
                      aria-label="Increase quantity"
                    >+</button>
                  </div>

                  {/* Subtotal */}
                  <div className="cart-item-subtotal">
                    ${(parseFloat(String(item.price).replace("$", "")) * item.quantity).toFixed(2)}
                  </div>

                  {/* Remove */}
                  <button
                    className="cart-remove-btn"
                    onClick={() => removeFromCart(item)}
                    aria-label="Remove item"
                  >
                    <TrashIcon />
                  </button>
                </div>
              ))}
            </div>

            {/* RIGHT — Summary */}
            <div className="cart-summary-panel">
              <h3 className="cart-summary-heading">Order Summary</h3>

              <div className="cart-summary-row">
                <span>Selected items</span>
                <span>{selectedItems.reduce((a, i) => a + i.quantity, 0)}</span>
              </div>

              <div className="cart-summary-row">
                <span>Email</span>
                <span className="cart-summary-email">{user?.email || "—"}</span>
              </div>

              <div className="cart-summary-divider" />

              <div className="cart-summary-row cart-summary-total">
                <span>Total</span>
                <span>${getSelectedTotal().toFixed(2)}</span>
              </div>

              <button
                className={`cart-pay-btn ${selectedItems.length === 0 ? "cart-pay-btn--disabled" : ""}`}
                onClick={handlePayment}
                disabled={selectedItems.length === 0}
              >
                Pay Selected Items
              </button>

              {selectedItems.length === 0 && (
                <p className="cart-pay-hint">Select items above to continue</p>
              )}
            </div>

          </div>
        )}
      </div>
    </div>
  );
};

export default CartPage;
